+        assert_eq!(lc_p, lc_buf.as_ptr());
+        let fl_s = unsafe { CStr::from_ptr(fl_p) }.to_bytes();
+        let lc_s = unsafe { CStr::from_ptr(lc_p) }.to_bytes();
+        assert_eq!(fl_s, lc_s, "truncated reentrant hostalias value");
